class Solution:
    def connectSticks(self, sticks: List[int]) -> int:
        """
        Return the minimum cost of connecting all the given sticks into one
        stick in this way.
        
        Examples:
        
        Example 1
        Input: sticks = [2, 4, 3]
        Output: 14
        
        Example 2
        Input: sticks = [1,8,3,5]
        Output: 30
        Explanation: You start with sticks = [1,8,3,5].
        heap = [1,3,5,8]
        stick = 1
        cur_cost = 1
        total_cost = 1
        1. Combine sticks 1 and 3 for a cost of 1 + 3 = 4. Now you have sticks = [4,8,5].
        2. Combine sticks 4 and 5 for a cost of 4 + 5 = 9. Now you have sticks = [9,8].
        3. Combine sticks 9 and 8 for a cost of 9 + 8 = 17. Now you have sticks = [17].
        There is only one stick left, so you are done. The total cost is 4 + 9 + 17 = 30.
        
        Example 3
        Input: sticks = [5]
        Output: 0
        """
        # want to collect all lowest
        heapify(sticks)
        # keep pushing/popping
        total_cost = 0
        while len(sticks) > 1:
            smallest_sticks = [heappop(sticks), heappop(sticks)]
            cur_stick = smallest_sticks[0] + smallest_sticks[1]
            total_cost += cur_stick
            heappush(sticks, cur_stick)
        return total_cost

