def format_diff(expected: Any, actual: Any) -> str:
    """Render a unified diff for mismatched expected and actual values."""
    expected_lines = pprint.pformat(expected, sort_dicts=False).splitlines()
    actual_lines = pprint.pformat(actual, sort_dicts=False).splitlines()
    diff = list(
        difflib.unified_diff(
            expected_lines,
            actual_lines,
            fromfile="expected",
            tofile="actual",
            lineterm="",
        )
    )
    return "\n".join(diff) if diff else "No diff."


